public Object answer(InvocationOnMock invocation) throws Throwable {
    // Check if the method is default (Java 8+) and part of an interface
    if (invocation.getMethod().isDefault()) {
        return invocation.callRealMethod();
    }
    // For other cases, check if the method is not abstract and belongs to a class
    if (!java.lang.reflect.Modifier.isAbstract(invocation.getMethod().getModifiers()) && !invocation.getMethod().getDeclaringClass().isInterface()) {
        return invocation.callRealMethod();
    }
    // Default to returning null for unsupported cases
    return null;
}

public Object answer(InvocationOnMock invocation) throws Throwable {
    if ((invocation.getMethod().getModifiers() & java.lang.reflect.Modifier.ABSTRACT) != 0) {
        return null;
    } else {
        return invocation.callRealMethod();
    }
}

public Object answer(InvocationOnMock invocation) throws Throwable {
    if (invocation.getMethod().getDeclaringClass().isInterface() || (invocation.getMethod().getModifiers() & java.lang.reflect.Modifier.ABSTRACT) != 0) {
        return null;
    } else {
        return invocation.callRealMethod();
    }
}
